import React, { useState, useEffect } from 'react';

function Patient() {
  const [lang, setLang] = useState('en');
  const [name, setName] = useState('');
  const [department, setDepartment] = useState('General');
  const [time, setTime] = useState('');
  const [day, setDay] = useState(new Date().toISOString().slice(0, 10));
  const [currentPatientId, setCurrentPatientId] = useState(null);
  const [queueInfo, setQueueInfo] = useState('');

  const texts = {
    en: ["Register Patient", "Full Name", "Department", "Time (HH:MM)", "Day", "Register"],
    ru: ["Регистрация пациента", "Полное имя", "Отделение", "Время (ЧЧ:ММ)", "День", "Зарегистрироваться"],
    kg: ["Пациентти каттоо", "Толук аты", "Бөлүм", "Убакыт (ЧЧ:ММ)", "Күн", "Катталуу"]
  };

  const switchLanguage = () => {
    setLang(lang === "en" ? "ru" : lang === "ru" ? "kg" : "en");
  };

  const registerPatient = async () => {
    try {
      const response = await fetch('/api/register-patient', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, department, time, day })
      });

      const data = await response.json();
      setCurrentPatientId(data.id);
    } catch (err) {
      console.error('Registration failed:', err);
    }
  };

  const updateQueueInfo = async () => {
    if (!currentPatientId) return;

    try {
      const response = await fetch(`/api/patients?day=${day}`);
      const allPatients = await response.json();
      const me = allPatients.find(p => p.id === currentPatientId);

      if (me) {
        const position = allPatients.filter(p => 
          p.department === me.department && 
          (p.status === "Waiting" || p.status === "In Progress") && 
          p.queueNumber <= me.queueNumber
        ).length;

        setQueueInfo(`Your Queue Number: ${me.queueNumber}, Position: ${position}, Status: ${me.status}`);
      }
    } catch (err) {
      console.error('Failed to update queue info:', err);
    }
  };

  useEffect(() => {
    if (currentPatientId) {
      updateQueueInfo();
      const interval = setInterval(updateQueueInfo, 3000);
      return () => clearInterval(interval);
    }
  }, [currentPatientId, day]);

  const t = texts[lang];

  return (
    <div className="container">
      <h2>{t[0]}</h2>

      <label>{t[1]}</label><br />
      <input
        value={name}
        onChange={(e) => setName(e.target.value)}
      /><br />

      <label>{t[2]}</label><br />
      <select
        value={department}
        onChange={(e) => setDepartment(e.target.value)}
      >
        <option>General</option>
        <option>Pediatrics</option>
        <option>Dentistry</option>
      </select><br />

      <label>{t[3]}</label><br />
      <input
        type="time"
        value={time}
        onChange={(e) => setTime(e.target.value)}
      /><br />

      <label>{t[4]}</label><br />
      <input
        type="date"
        value={day}
        onChange={(e) => setDay(e.target.value)}
      /><br />

      <button onClick={registerPatient}>{t[5]}</button>
      <button onClick={switchLanguage} className="lang">Switch Language</button>

      {queueInfo && (
        <h3>
          <span className={`status-${queueInfo.includes('Waiting') ? 'Waiting' : queueInfo.includes('In Progress') ? 'InProgress' : ''}`}>
            {queueInfo}
          </span>
        </h3>
      )}
    </div>
  );
}

export default Patient;
